/**
 * Generic helper: require session, extract params, call RPC, return standardized response.
 */
async function callNoteRpc(
  request: FastifyRequest,
  reply: FastifyReply,
  rpcName: string,
  paramBuilder?: (q: Record<string, unknown>, session: { duz?: string }) => string[]
): Promise<void> {
  const session = await requireSession(request, reply);
  const q = (request.query as Record<string, unknown>) || {};
  const params = paramBuilder ? paramBuilder(q, session) : [q?.dfn, q?.docIen ?? q?.ien].filter(Boolean).map(String);
  try {
    const lines = await safeCallRpc(rpcName, params);
    return reply.send({
      ok: true,
      source: 'vista',
      rpcUsed: [rpcName],
      data: lines,
      pendingTargets: [],
    });
  } catch (err: unknown) {
    const msg = err instanceof Error ? err.message : String(err);
    log.warn(`${rpcName} failed`, { err: msg });
    return reply.code(502).send({
      ok: false,
      source: 'vista',
      error: msg,
      rpcUsed: [],
      pendingTargets: [rpcName],
    });
  }
}

